import{_ as a,o as r,c as o,ae as t}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Create QR Codes","description":"","frontmatter":{"title":"Create QR Codes","slug":"create-qr-codes"},"headers":[],"relativePath":"marketer-hub/create-qr-codes.md","filePath":"marketer-hub/create-qr-codes.md"}'),n={name:"marketer-hub/create-qr-codes.md"};function i(s,e,d,c,l,h){return r(),o("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>Explore Branch’s new linking experience for <a href="https://help.branch.io/docs/create-web-links-1#view-and-manage-links" target="_blank" rel="noreferrer">Web Links</a> and <a href="https://help.branch.io/docs/create-app-links-new" target="_blank" rel="noreferrer">App Links</a>, which offer deep linking, flexible configuration, and link analysis across multiple platforms.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Within the Branch Dashboard, you can create, customize, and manage all of your QR Codes.</p><p>These QR Codes, powered by Branch Links, allow you to round out your marketing efforts to drive more users from places offline/in-person, video advertisements, and more!</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><h3 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h3><p>Access to QR Codes requires a premium plan. Please contact our <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">Sales team</a> to learn more about pricing and availability.</p><h4 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h4><p>To access the QR Codes <a href="https://branch.dashboard.branch.io/qr-codes/manager" target="_blank" rel="noreferrer">page</a> in the Branch Dashboard, which includes the <strong>Manager</strong> and <strong>Analytics</strong> tabs, the following must be true:</p><ul><li>For <strong>App-Level Settings</strong>, you have <strong>View</strong> permissions</li><li>For <strong>Link-Level Settings</strong>, you have <strong>View</strong> permissions</li><li>Under <strong>Feature Filters</strong>, you must have <strong>Restrict link creation and editing to templates</strong> disabled</li><li>You are <strong>not</strong> an agency user</li></ul><p>To manage and update your team&#39;s access settings, go to the <strong>Teams</strong> <a href="https://branch.dashboard.branch.io/account-settings/team" target="_blank" rel="noreferrer">tab</a> on the <strong>Account Settings</strong> page.</p><h3 id="redirection-behavior-for-printed-qr-codes" tabindex="-1">Redirection behavior for printed QR codes <a class="header-anchor" href="#redirection-behavior-for-printed-qr-codes" aria-label="Permalink to &quot;Redirection behavior for printed QR codes&quot;">​</a></h3><p>Changing a QR code&#39;s redirection between app linking and web-only (or vice versa) can change the underlying link URL. If the URL changes, any previously printed QR codes will no longer point to the updated destination.</p><p>How this behaves depends on your package:</p><ul><li><strong>Engagement (Legacy):</strong> Toggling between app and web-only changes the link domain (for example., <code>mybrand.app.link</code> → <code>mybrand-web.app.link</code>), requiring a reprint.</li><li><strong>Activation:</strong> By default, the URL will not change when toggling. However, if you have configured separate web vs. app routing domains, the link may change, requiring a reprint.</li></ul><p>Finalize your redirection strategy before printing.</p><h2 id="qr-code-creation" tabindex="-1">QR Code Creation <a class="header-anchor" href="#qr-code-creation" aria-label="Permalink to &quot;QR Code Creation&quot;">​</a></h2><p>The steps below outline how to create a Branch QR Code. They walk you through the different layers of information you can add to your Branch QR Code to make it easier to analyze, look like your brand, and more.</p><h3 id="_1-create-qr-code" tabindex="-1">1. Create QR Code <a class="header-anchor" href="#_1-create-qr-code" aria-label="Permalink to &quot;1. Create QR Code&quot;">​</a></h3><p>In the Branch Dashboard, navigate to the <strong>Manger</strong> <a href="https://dashboard.branch.io/qr-codes/manager" target="_blank" rel="noreferrer">tab</a> of the <strong>QR Codes</strong> <a href="https://dashboard.branch.io/qr-codes/" target="_blank" rel="noreferrer">section</a>, then click the <strong>+ Create QR Code</strong> button.</p><h3 id="_2-define-qr-code" tabindex="-1">2. Define QR Code <a class="header-anchor" href="#_2-define-qr-code" aria-label="Permalink to &quot;2. Define QR Code&quot;">​</a></h3><p>You must define your Branch QR Code with a <strong>Title</strong> and an <strong>Original Web URL</strong>.</p><p>Enter the values for these fields in their respective boxes.</p><p>It is recommended that you use a title that is descriptive of your campaign.</p><p>Click <strong>Create QR Code Now</strong> to generate your Branch QR Code or <strong>Save &amp; Continue</strong> to configure your Branch QR Code further.</p><h3 id="_3-add-analytics-tags" tabindex="-1">3. Add Analytics Tags <a class="header-anchor" href="#_3-add-analytics-tags" aria-label="Permalink to &quot;3. Add Analytics Tags&quot;">​</a></h3><p>Similar to <a href="./create-quick-links.html">Branch Short Links</a>, you can add your <strong>Analytics Tags</strong> here.</p><p>It is recommended that you add proper analytics tags to your Branch QR Codes to better analyze your campaign performance.</p><p>Click <strong>Create QR Code Now</strong> to generate your Branch QR Code or click <strong>Save &amp; Continue</strong> to configure your Branch QR Code further.</p><h3 id="_4-configure-redirects" tabindex="-1">4. Configure Redirects <a class="header-anchor" href="#_4-configure-redirects" aria-label="Permalink to &quot;4. Configure Redirects&quot;">​</a></h3><p>In the <strong>Redirects</strong> section, you can determine what happens if the user scans the Branch QR Code and doesn&#39;t have your app installed.</p><p>You can configure the behavior to route the user to the app store, a webpage, or a <a href="./deepviews.html">Branch Deepview</a>.</p><p>Click <strong>Create QR Code Now</strong> to generate your Branch QR Code or click <strong>Save &amp; Continue</strong> to configure your Branch QR Code further.</p><h3 id="_5-add-link-data" tabindex="-1">5. Add Link Data <a class="header-anchor" href="#_5-add-link-data" aria-label="Permalink to &quot;5. Add Link Data&quot;">​</a></h3><p>The <strong>Link Data</strong> section is for adding additional information about your Branch Link to your Branch QR Code.</p><p>These <strong>Key</strong> and <strong>Value</strong> pairs will be passed to the user&#39;s app session and can be used for additional analytics or deep linking.</p><p>Click <strong>Create QR Code Now</strong> to generate your Branch QR Code or click <strong>Save &amp; Continue</strong> to configure your Branch QR Code further.</p><h3 id="_6-customize-qr-code" tabindex="-1">6. Customize QR Code <a class="header-anchor" href="#_6-customize-qr-code" aria-label="Permalink to &quot;6. Customize QR Code&quot;">​</a></h3><p>Finally, you can customize your QR code. In the <strong>Customize</strong> section, you can edit the <strong>Finder Style</strong>, <strong>Code Pattern</strong>, <strong>Colors</strong>, and <strong>Center Logo</strong>.</p><p>Click <strong>Create QR Code Now</strong> to generate your Branch QR Code.</p><h3 id="_7-download-qr-code" tabindex="-1">7. Download QR Code <a class="header-anchor" href="#_7-download-qr-code" aria-label="Permalink to &quot;7. Download QR Code&quot;">​</a></h3><p>Once complete, you can download your Branch QR Code as a PNG, JPEG, or SVG.</p><h4 id="file-format-best-practices" tabindex="-1">File Format Best Practices <a class="header-anchor" href="#file-format-best-practices" aria-label="Permalink to &quot;File Format Best Practices&quot;">​</a></h4><p>Branch QR Codes are designed to be high resolution - any file format you download will give you a Branch QR Code with a resolution of <strong>300 pixels per inch</strong> and an image size of <strong>1667 x 1667 pixels</strong>.</p><p>However, each file format (PNG, JPEG, and SVG) has its different use cases and benefits. Which one you should use depends on how you plan to use your Branch QR Code.</p><ul><li><strong>PNG</strong>: Recommended for most general use cases. Larger file size. Not transparent.</li><li><strong>JPEG</strong>: Recommended for most general use cases. This includes digital content and printed materials. Not transparent.</li><li><strong>SVG</strong>: Recommended when being able to resize the image without losing quality is essential. This could include high-quality print materials (posters, flyers, large banners) or certain websites. Transparent background.</li></ul>',46)])])}const p=a(n,[["render",i]]);export{u as __pageData,p as default};
